export function parseInput(raw: string): number | null {
  const trimmed = raw.trim();
  const n = Number(trimmed);
  if (isNaN(n)) return null;
  return n;
}

export interface Frobable {
  frob(): string;
  frobTwice(): string;
  readonly name: string;
  readonly tags: string[];
  count: number;
  reset(): void;
}

export class Foo implements Frobable {
  constructor(
    public readonly name: string,
    public value: number,
    public tags: string[] = [],
  ) {}
  frob(): string { return this.name; }
  frobTwice(): string { return this.name.repeat(2); }
  reset(): void { this.value = 0; }
}

export class Foo {
  double(): number {
    const result = this.value * 2;
    if (result > Number.MAX_SAFE_INTEGER) {
      return Number.MAX_SAFE_INTEGER;
    }
    return result;
  }
}

export class Foo {
  triple(): number {
    const result = this.value * 3;
    if (result > Number.MAX_SAFE_INTEGER) {
      return Number.MAX_SAFE_INTEGER;
    }
    return result;
  }
}

